import os
from google.cloud import storage
from keras.models import load_model

def get_latest_version(bucket_name, model_path):
    blobs = storage.Client().list_blobs(bucket_name, prefix=model_path)
    versions = [int(blob.name.split('/')[-1].split('.')[0]) for blob in blobs]
    return max(versions) if versions else None

def load_latest_model():
    bucket_name = os.environ['BUCKET_NAME']
    model_path = os.environ['MODEL_PATH']
    
    latest_version = get_latest_version(bucket_name, model_path)
    if latest_version is not None:
        blob = storage.Client().bucket(bucket_name).blob(f'{model_path}/{latest_version}')
        file_name = f'/tmp/{latest_version}'  # Temporary location for model loading
        blob.download_to_filename(file_name)
        
        return load_model(file_name)
    else:
        print("No models found in the specified path.")
        return None